def _sort_palette(self, sort_palette):
    """
    Reorders the palette of a "P" mode image, without changing its
    appearance. Used internally by
    :py:meth:`~PIL.Image.Image.quantize`.

    :param sort_palette: ``"luminance"``, ``"rgb"``, or a callable
       that is given a color tuple and returns a sort key.
    """
    mode = self.palette.mode
    mode_len = len(mode)
    palette = self.palette.palette
    num_colors = len(palette) // mode_len
    colors = [
        tuple(palette[i * mode_len : (i + 1) * mode_len])
        for i in range(num_colors)
    ]

    if callable(sort_palette):
        key = sort_palette
    elif sort_palette == "luminance":

        def key(color):
            r, g, b = color[:3]
            return r * 299 + g * 587 + b * 114

    elif sort_palette == "rgb":

        def key(color):
            return color

    else:
        raise ValueError("sort_palette must be 'luminance', 'rgb', or a callable")

    order = sorted(range(num_colors), key=lambda i: key(colors[i]))

    table = list(range(256))
    for new_index, old_index in enumerate(order):
        table[old_index] = new_index

    im = self.point(table)
    im.putpalette(
        b"".join(bytes(colors[old_index]) for old_index in order), rawmode=mode
    )
    return im

